import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

function MovieRow({ title, movies = [] }) {
  return (
    <section className="section">
      <h2 className="section-title">{title}</h2>
      <div className="movies-row">
        {movies.map((movie) => (
          <Link
            key={movie._id}
            to={`/movie/${movie._id}`}
            className="movie-card"
            style={{ width: '220px', height: '320px' }}
          >
            <img src={movie.thumbnail} alt={movie.title} loading="lazy" />
            <div className="card-overlay">
              <div className="card-title">{movie.title}</div>
              <div className="card-meta">
                <span>{movie.year}</span>
                <span>•</span>
                <span className="card-rating">{movie.rating?.toFixed(1) || 'N/A'}</span>
              </div>
            </div>
          </Link>
        ))}
      </div>
    </section>
  );
}

export default function HomePage() {
  const { API } = useAuth();
  const [featured, setFeatured] = useState([]);
  const [trending, setTrending] = useState([]);

  useEffect(() => {
    let mounted = true;
    Promise.all([
      axios.get(`${API}/movies/featured`),
      axios.get(`${API}/movies/trending`),
    ])
      .then(([f, t]) => {
        if (!mounted) return;
        setFeatured(f.data || []);
        setTrending(t.data || []);
      })
      .catch(() => {
        if (!mounted) return;
        setFeatured([]);
        setTrending([]);
      });

    return () => {
      mounted = false;
    };
  }, [API]);

  return (
    <main className="page" style={{ padding: '100px 24px 32px' }}>
      <MovieRow title="Featured" movies={featured} />
      <MovieRow title="Trending" movies={trending} />
    </main>
  );
}
